function string.IsNullOrEmpty(a)return a==nil or a==""end;function string.Contains(b,c)return string.find(b,c,1,true)~=nil end;function string.StartsWith(b,c)return string.sub(b,1,#c)==c end;function string.EndsWith(b,c)return string.sub(b,-#c)==c end;function string.IndexOf(b,c,d)local e=string.find(b,c,(d or 0)+1,true)return e and e-1 or-1 end;function string.LastIndexOf(b,c)local f=-1;local e=1;while true do local g=string.find(b,c,e,true)if not g then break end;f=g-1;e=g+1 end;return f end;function string.Replace(b,h,i)return string.gsub(b,h,i)end;function string.Substring(b,d,j)if j then return string.sub(b,d+1,d+j)else return string.sub(b,d+1)end end;function string.Split(b,k)local l={}local m=string.format("([^%s]+)",k)for n in string.gmatch(b,m)do table.insert(l,n)end;return l end;function string.Trim(b)return b:match("^%s*(.-)%s*$")end;function string.ToUpper(b)return string.upper(b)end;function string.ToLower(b)return string.lower(b)end;function string.ByteLength(b)return#b end;function string.Length(b)return utf8.len(b)or 0 end